// Profit tier classifier
const items = $input.all();
const PROFIT_TIERS = { SS: 0.85, S: 0.80, A: 0.75, B: 0.70 };
const EMS = [{max:100,jpy:1350},{max:250,jpy:1750},{max:500,jpy:2150},{max:1000,jpy:3100}];
const usdJpy = 150;

function ems(gram){ return (EMS.find(b => gram <= b.max) || {jpy:4000}).jpy; }
function tier(margin){ if(margin>=0.85) return 'SS'; if(margin>=0.80) return 'S'; if(margin>=0.75) return 'A'; if(margin>=0.70) return 'B'; return 'OUT'; }

return items.map(i => {
  const d = i.json;
  const costJpy = d.cost_jpy || 0;
  const weightG = d.weight_g || 500;
  const priceUsd = d.price_usd || 0;
  const revenueJpy = priceUsd * usdJpy;
  const totalCost = costJpy + ems(weightG) + 300; // +300 packaging
  const margin = (revenueJpy - totalCost) / revenueJpy;
  return { json: { ...d, margin, tier: tier(margin), ems_jpy: ems(weightG) } };
}).filter(x => x.json.tier !== 'OUT');
